const src = $json || {};

const fromKnownNode = (name) => {
  try {
    const item = $(name).first();
    if (item && item.json && Object.keys(item.json).length) return item.json;
  } catch (e) {}
  return null;
};

const fallbackNodes = [
  'Read Rows',
  'Google Sheets',
  'Get row(s) in sheet',
  'Rows',
  'Sheet Row',
  'Get Sheet Row'
];

let row = (src.row && typeof src.row === 'object')
  ? src.row
  : ((src.data && typeof src.data === 'object') ? src.data : src);

if (!Object.keys(row || {}).length) {
  for (const nodeName of fallbackNodes) {
    const candidate = fromKnownNode(nodeName);
    if (candidate) {
      row = candidate;
      break;
    }
  }
}

const normalize = (s) => String(s || '')
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .replace(/\s+/g, ' ')
  .trim();

const normalizedRow = {};
for (const [k, v] of Object.entries(row || {})) {
  normalizedRow[normalize(k)] = v;
}

const pick = (...keys) => {
  for (const k of keys) {
    const direct = row[k];
    if (direct !== undefined && direct !== null && String(direct).trim() !== '') return String(direct).trim();

    const norm = normalizedRow[normalize(k)];
    if (norm !== undefined && norm !== null && String(norm).trim() !== '') return String(norm).trim();
  }
  return '';
};

const availableKeys = Object.keys(row || {});
if (!availableKeys.length) {
  throw new Error('Input row is empty. Připoj před tuto větev node se záznamem z listu Vytipované weby.');
}

const emailRaw = pick('Email adresa', 'Email  adresa', 'Email', 'email', 'E-mail');
const to = emailRaw.includes(',') ? emailRaw.split(',')[0].trim() : emailRaw;

const subject = pick('Email predmet', 'Email předmět', 'Predmet', 'Předmět', 'subject');
const body = pick('Email telo', 'Email tělo', 'Telo', 'Tělo', 'body');
const screenshotAfterUrl = pick('Screenshot URL', 'Screenshot Url', 'screenshotAfterUrl', 'afterScreenshotUrl');
const screenshotBeforeUrl = pick('Before Screenshot URL', 'Before screenshot URL', 'beforeScreenshotUrl', 'screenshotBeforeUrl');

const missing = [];
if (!to) missing.push('Email adresa/Email');
if (!subject) missing.push('Email predmet');
if (!body) missing.push('Email telo');
if (!screenshotAfterUrl) missing.push('Screenshot URL');
if (!screenshotBeforeUrl) missing.push('Before Screenshot URL');

if (missing.length) {
  throw new Error(`Missing required columns: ${missing.join(', ')} | Available keys: ${availableKeys.join(', ')}`);
}

return [{
  json: {
    ...row,
    to,
    subject,
    body,
    screenshotAfterUrl,
    screenshotBeforeUrl
  }
}];

const mail = $('Prepare + Validate Email From Sheet').first();
const shotAfter = $('Get Screenshot (After)').first();
const shotBefore = $('Get Screenshot (Before)').first();

const bAfter = shotAfter?.binary?.data || shotAfter?.binary?.file;
const bBefore = shotBefore?.binary?.data || shotBefore?.binary?.file;

if (!mail?.json?.to) throw new Error('Chybí příjemce: sloupec Email adresa nebo Email.');
if (!mail?.json?.subject) throw new Error('Chybí předmět: sloupec Email predmet.');
if (!mail?.json?.body) throw new Error('Chybí tělo: sloupec Email telo.');
if (!bAfter || !bBefore) throw new Error('Chybí screenshoty: Screenshot URL / Before Screenshot URL.');

return [{
  json: {
    to: String(mail.json.to).trim(),
    subject: String(mail.json.subject),
    body: String(mail.json.body)
  },
  binary: {
    screenshot1: {
      ...bAfter,
      fileName: bAfter.fileName || 'after-screenshot.jpg'
    },
    screenshot2: {
      ...bBefore,
      fileName: bBefore.fileName || 'before-screenshot.jpg'
    }
  }
}];

const out = $input.first()?.json || {};
const draftId = out.id || out.draftId || out.data?.id || out.data?.draftId || out.result?.id;
const messageId = out.message?.id || out.messageId || out.data?.message?.id || null;

if (!draftId) {
  throw new Error(`Gmail node doběhl bez draft ID. Výstup: ${JSON.stringify(out)}`);
}

const composeToken = messageId || draftId;
const draftUrl = `https://mail.google.com/mail/u/0/#drafts?compose=${composeToken}`;

return [{
  json: {
    ...out,
    draftId,
    messageId,
    draftCreated: true,
    draftUrl
  }
}];
